import Foundation
import Testing

@testable import FSRS

// MARK: - Long sequence byte-parity vs ts-fsrs reference
//
// The existing parity suite (`ts-fsrs parity` in FSRSTests.swift) only
// pins three steps of an all-Good Sequence A. This file extends the byte-
// parity contract over LONG mixed-rating sequences (50+ steps) in both
// scheduler modes, plus a handful of targeted edge scenarios.
//
// Reference values were generated by /tmp/fsrs_ref.py + /tmp/sim_fsrs.py,
// which reproduce ts-fsrs algorithm.ts and basic_scheduler.ts /
// long_term_scheduler.ts exactly. Both reference scripts are validated
// against ts-fsrs' own FSRS-6.test.ts (`ivl_history` and `memory state`
// tests reproduce to all 8 rounded decimals).
//
// Timing convention: every review fires at `card.due`. With Swift's
// `refDate = 06:13:20 UTC` and the scheduler computing `due = lastReview
// + scheduledDays * 86400`, the time-of-day stays fixed across reviews,
// so `Card.elapsedDays(now:)` returns exactly `card.scheduledDays` UTC-day
// crossings — matching the integer `t` the reference passes to
// `next_state`.
//
// All numeric assertions use exact `==` (no tolerance). The point of this
// suite is to prove byte-identical S/D, scheduledDays, reps, and lapses
// across long sequences — divergence at any step is a real bug and the
// failing test should be left in place to localise it.

/// One row of a reference trajectory: rating to apply at that step, plus
/// the expected post-review card state.
private struct Step {
    let rating: Rating
    let stability: Double
    let difficulty: Double
    let scheduledDays: Int
    let reps: Int
    let lapses: Int
}

/// Drives a card through `steps` using `fsrs`, reviewing each time at the
/// card's current `due` date. Asserts every observable field at every step.
///
/// Splitting the loop into a helper keeps the assertion logic identical
/// across all sequences (so a parity break can be diagnosed by reading
/// one helper, not 50 inlined #expect calls).
private func runSequence(
    label: String,
    fsrs: FSRS,
    initialCard: Card = FSRS.createCard(now: refDate),
    initialNow: Date = refDate,
    steps: [Step],
    sourceLocation: SourceLocation = #_sourceLocation
) {
    var card = initialCard
    var now = initialNow
    for (i, step) in steps.enumerated() {
        let humanIndex = i + 1  // 1-indexed for failure messages
        card = fsrs.schedule(card: card, now: now, rating: step.rating).card
        #expect(
            card.stability == step.stability,
            "[\(label)] step \(humanIndex) (\(step.rating)): stability \(card.stability) ≠ expected \(step.stability)",
            sourceLocation: sourceLocation
        )
        #expect(
            card.difficulty == step.difficulty,
            "[\(label)] step \(humanIndex) (\(step.rating)): difficulty \(card.difficulty) ≠ expected \(step.difficulty)",
            sourceLocation: sourceLocation
        )
        #expect(
            card.scheduledDays == step.scheduledDays,
            "[\(label)] step \(humanIndex) (\(step.rating)): scheduledDays \(card.scheduledDays) ≠ expected \(step.scheduledDays)",
            sourceLocation: sourceLocation
        )
        #expect(
            card.reps == step.reps,
            "[\(label)] step \(humanIndex) (\(step.rating)): reps \(card.reps) ≠ expected \(step.reps)",
            sourceLocation: sourceLocation
        )
        #expect(
            card.lapses == step.lapses,
            "[\(label)] step \(humanIndex) (\(step.rating)): lapses \(card.lapses) ≠ expected \(step.lapses)",
            sourceLocation: sourceLocation
        )
        now = card.due
    }
}

