// MARK: - Targeted edge scenarios

@Suite("Long sequence parity — edge scenarios")
struct EdgeSequenceParityTests {

    /// Repeated lapse-relearn cycles in basic mode. Pattern: G, G, then
    /// alternating Again/Good four times. Each Again sends the card from
    /// Review → Relearning at step 0 (10-minute relearning step). The
    /// next Good then graduates back to Review with a small FSRS
    /// interval. Tests that:
    ///   - Lapses increment monotonically on Again-on-Review
    ///   - Difficulty climbs toward 10 under repeated failures (mean
    ///     reversion is overwhelmed by the +w[6] step on Again)
    ///   - Stability collapses then recovers after each cycle
    @Test("Lapse-relearn cycle (basic mode, 10 reviews)")
    func lapseRelearnCycle() {
        let fsrs = FSRS()
        let steps: [Step] = [
            Step(rating: .good, stability: 2.30650000, difficulty: 2.11810397, scheduledDays: 0, reps: 1, lapses: 0),
            Step(rating: .good, stability: 2.30650000, difficulty: 2.11121424, scheduledDays: 2, reps: 2, lapses: 0),
            Step(rating: .again, stability: 0.60770166, difficulty: 7.39223814, scheduledDays: 0, reps: 3, lapses: 1),
            Step(rating: .good, stability: 0.65979762, difficulty: 7.38007427, scheduledDays: 1, reps: 4, lapses: 1),
            Step(rating: .again, stability: 0.23203410, difficulty: 9.12407659, scheduledDays: 0, reps: 5, lapses: 2),
            Step(rating: .good, stability: 0.26840194, difficulty: 9.11018088, scheduledDays: 1, reps: 6, lapses: 2),
            Step(rating: .again, stability: 0.11831252, difficulty: 9.69275088, scheduledDays: 0, reps: 7, lapses: 3),
            Step(rating: .good, stability: 0.14305810, difficulty: 9.67828650, scheduledDays: 1, reps: 8, lapses: 3),
            Step(rating: .again, stability: 0.07231756, difficulty: 9.87948333, scheduledDays: 0, reps: 9, lapses: 4),
            Step(rating: .good, stability: 0.09032182, difficulty: 9.86483222, scheduledDays: 1, reps: 10, lapses: 4),
        ]
        runSequence(label: "lapseRelearn", fsrs: fsrs, steps: steps)
    }

    /// Easy from a new card graduates immediately to Review with the
    /// initial S₀(.easy) = w[3] = 8.2956 → 8 days. Subsequent Easy
    /// reviews compound the easy bonus (w[16] = 1.8729). Difficulty
    /// stays clamped at 1.0 because mean-reversion + linear-damping at
    /// D=1 gives a value ≤ 1, which clamps back to 1.
    ///
    /// This tests both the new-card Easy graduation path and the recall
    /// stability formula's easy bonus over many compounded steps.
    @Test("Easy graduation from new — 5 consecutive Easy reviews (basic mode)")
    func easyGraduationCascade() {
        let fsrs = FSRS()
        let steps: [Step] = [
            Step(rating: .easy, stability: 8.29560000, difficulty: 1.00000000, scheduledDays: 8, reps: 1, lapses: 0),
            Step(rating: .easy, stability: 65.62422648, difficulty: 1.00000000, scheduledDays: 66, reps: 2, lapses: 0),
            Step(rating: .easy, stability: 396.77501923, difficulty: 1.00000000, scheduledDays: 397, reps: 3, lapses: 0),
            Step(rating: .easy, stability: 1874.91696522, difficulty: 1.00000000, scheduledDays: 1875, reps: 4, lapses: 0),
            Step(rating: .easy, stability: 7265.43276492, difficulty: 1.00000000, scheduledDays: 7265, reps: 5, lapses: 0),
        ]
        runSequence(label: "easyCascade", fsrs: fsrs, steps: steps)
    }

    /// Three sibling cards taken to Review state (long-term mode, S=2.3065,
    /// scheduledDays=3). Then each is reviewed Good at a different time
    /// relative to its due date:
    ///   - exactly at due (t = 3 days)
    ///   - 2 days early   (t = 1 day)
    ///   - 5 days late    (t = 8 days)
    ///
    /// The forgetting curve gives lower R for larger t, which feeds into
    /// the recall stability formula's spacing-effect term `(exp(w[10]×(1-R)) - 1)`.
    /// Larger t → lower R → bigger stability gain on Good.
    @Test("Review timing: at-due vs early vs overdue (long-term mode)")
    func reviewTimingVariants() {
        let fsrs = FSRS(parameters: Parameters(enableShortTerm: false))
        let baseCard = FSRS.createCard(now: refDate)
        // Bring all three siblings to the same Review state via long-term
        // Good. After this step: S=2.3065, D=2.11810397, scheduledDays=3,
        // due = refDate + 3 days.
        let warmed = fsrs.schedule(card: baseCard, now: refDate, rating: .good).card
        #expect(warmed.stability == 2.30650000)
        #expect(warmed.difficulty == 2.11810397)
        #expect(warmed.scheduledDays == 3)

        // At due (t = 3 days)
        let atDue = fsrs.schedule(
            card: warmed, now: dateAfter(days: 3), rating: .good
        ).card
        #expect(atDue.stability == 13.82690327)
        #expect(atDue.difficulty == 2.11121424)
        #expect(atDue.scheduledDays == 14)

        // 2 days early (t = 1 day): higher R, smaller stability gain
        let early = fsrs.schedule(
            card: warmed, now: dateAfter(days: 1), rating: .good
        ).card
        #expect(early.stability == 7.31530068)
        #expect(early.difficulty == 2.11121424)  // D update is t-independent
        #expect(early.scheduledDays == 7)

        // 5 days late (t = 8 days): lower R, larger stability gain
        let late = fsrs.schedule(
            card: warmed, now: dateAfter(days: 8), rating: .good
        ).card
        #expect(late.stability == 22.76818035)
        #expect(late.difficulty == 2.11121424)
        #expect(late.scheduledDays == 23)

        // Spacing-effect ordering: late > at-due > early.
        #expect(early.stability < atDue.stability)
        #expect(atDue.stability < late.stability)
    }

    /// Reproduces ts-fsrs FSRS-6.test.ts `ivl_history` test verbatim:
    /// 13 ratings G,G,G,G,G,G,A,A,G,G,G,G,G in basic mode produce
    /// scheduled_days `[0, 2, 11, 46, 163, 498, 0, 0, 2, 4, 7, 12, 21]`.
    ///
    /// This is a direct lift from the canonical ts-fsrs test suite — if
    /// any single value diverges, Swift has drifted from the reference.
    @Test("ts-fsrs FSRS-6 ivl_history reproduction (basic mode)")
    func ivlHistoryReproduction() {
        let fsrs = FSRS()
        var card = FSRS.createCard(now: refDate)
        var now = refDate
        let ratings: [Rating] = [
            .good, .good, .good, .good, .good, .good,
            .again, .again,
            .good, .good, .good, .good, .good,
        ]
        let expectedIntervals: [Int] = [0, 2, 11, 46, 163, 498, 0, 0, 2, 4, 7, 12, 21]
        var observed: [Int] = []
        for rating in ratings {
            card = fsrs.schedule(card: card, now: now, rating: rating).card
            observed.append(card.scheduledDays)
            now = card.due
        }
        #expect(observed == expectedIntervals)
    }

    /// Reproduces ts-fsrs FSRS-6.test.ts `memory state[short-term]`:
    /// ratings A,G,G,G,G,G with gaps `[0, 0, 1, 3, 8, 21]` days produce
    /// final `S ≈ 53.62691, D ≈ 6.3574867` (4-decimal tolerance in the
    /// reference test). Swift's deterministic output should land within
    /// 1e-4 of those targets — values are quoted from the reference, so
    /// any larger gap is a real divergence.
    @Test("ts-fsrs FSRS-6 memory state[short-term] reproduction")
    func memoryStateShortTerm() {
        let fsrs = FSRS()  // basic mode = enableShortTerm
        var card = FSRS.createCard(now: refDate)
        var now = refDate
        let seq: [(Rating, Int)] = [
            (.again, 0), (.good, 0), (.good, 1), (.good, 3), (.good, 8), (.good, 21),
        ]
        for (rating, gapDays) in seq {
            now = now.addingTimeInterval(Double(gapDays) * 86400.0)
            card = fsrs.schedule(card: card, now: now, rating: rating).card
        }
        // ts-fsrs uses toBeCloseTo(...4) which compares within 5e-5.
        // We assert tighter (1e-4) to leave headroom but flag any real drift.
        #expect(abs(card.stability - 53.62691) < 1e-4,
                "stability \(card.stability) ≠ 53.62691 ± 1e-4")
        #expect(abs(card.difficulty - 6.3574867) < 1e-4,
                "difficulty \(card.difficulty) ≠ 6.3574867 ± 1e-4")
    }

    /// Reproduces ts-fsrs FSRS-6.test.ts `memory state[long-term]`:
    /// same ratings + gaps as the short-term variant, but every review
    /// goes through the long-term scheduler. Final `S ≈ 53.335106,
    /// D ≈ 6.3574867`.
    @Test("ts-fsrs FSRS-6 memory state[long-term] reproduction")
    func memoryStateLongTerm() {
        let fsrs = FSRS(parameters: Parameters(enableShortTerm: false))
        var card = FSRS.createCard(now: refDate)
        var now = refDate
        let seq: [(Rating, Int)] = [
            (.again, 0), (.good, 0), (.good, 1), (.good, 3), (.good, 8), (.good, 21),
        ]
        for (rating, gapDays) in seq {
            now = now.addingTimeInterval(Double(gapDays) * 86400.0)
            card = fsrs.schedule(card: card, now: now, rating: rating).card
        }
        #expect(abs(card.stability - 53.335106) < 1e-4,
                "stability \(card.stability) ≠ 53.335106 ± 1e-4")
        #expect(abs(card.difficulty - 6.3574867) < 1e-4,
                "difficulty \(card.difficulty) ≠ 6.3574867 ± 1e-4")
    }
}
